// Compliant: Clean expressions without redundant parentheses
func calculate(a, b, c int) int {
    // Natural operator precedence
    result := (a + b) * c // Parentheses needed for precedence

    // Simple return
    return result + 1
}

// Compliant: Clear conditions without extra grouping
func checkConditions(x, y, z int) bool {
    // Clear boolean logic
    if x > 0 && y > 0 {
        return true
    }

    // Simple boolean expression
    return x == y || z == 0
}

// Compliant: Parentheses used only when needed for clarity
func processData(data []int) {
    // No unnecessary parentheses
    length := len(data)
    average := sum(data) / length

    // Function calls without extra grouping
    result := process(average)

    // Clean slice operations
    subset := data[0:length/2]

    // Type assertion without extra parentheses
    value := interface{}(result)
}

// Compliant: Parentheses used strategically for clarity
func complexCalculation(a, b, c, d float64) float64 {
    numerator := a*b + c*d
    denominator := a + b + c + d
    return numerator / denominator
}

// Compliant: When parentheses improve readability
func readableExpressions(x, y, z int) int {
    // Parentheses clarify intent in complex expressions
    result := (x + y) * z // Needed for precedence

    // Parentheses help with complex boolean logic
    if (x > 10 && y > 10) || (z < 0) {
        return result * 2
    }

    // Function calls with complex parameters
    return max((x + y), (z * 2))
}

// Compliant: Parentheses for multi-line readability
func multiLineCondition(user User, config Config) bool {
    return user.IsActive &&
           user.IsVerified &&
           (config.AllowGuests || user.IsPremium) && // Parentheses clarify intent
           !user.IsBanned
}
